import React, { useEffect, useState, useCallback } from 'react';
import {
  Card,
  Button,
  dispatchAppToast,
} from '@linm-soft-org/linm-web-common-components';
import {
  Title,
  Text,
  Tag,
  Modal,
  Popconfirm,
  Space,
  Spin,
} from '@/components/common';
import { useAppDispatch } from '../../../store/hooks';
import { fpcService } from '../../../services/fpc/service';
import type { VarianceLogEntryDto, CreateVarianceLogDto, UpdateVarianceLogDto } from '../../../services/fpc/types';
import styles from './VarianceLogPage.module.css';

const STATUS_COLORS: Record<string, string> = {
  Open: 'orange',
  InProgress: 'blue',
  Closed: 'green',
};

const STATUS_LABELS: Record<string, string> = {
  Open: 'Mở',
  InProgress: 'Đang xử lý',
  Closed: 'Đã đóng',
};

const REASON_OPTIONS = [
  { value: 'Price', label: 'Giá' },
  { value: 'Volume', label: 'Sản lượng' },
  { value: 'Timing', label: 'Thời điểm' },
  { value: 'ExchangeRate', label: 'Tỷ giá' },
  { value: 'Other', label: 'Khác' },
];

const STATUS_OPTIONS = [
  { value: 'Open', label: 'Mở' },
  { value: 'InProgress', label: 'Đang xử lý' },
  { value: 'Closed', label: 'Đã đóng' },
];

const PAGE_SIZE = 20;

interface FormValues {
  categoryCode: string;
  planAmount: number;
  actualAmount: number;
  reasonCode: string;
  reasonDetail: string;
  owner: string;
  status: string;
  deadline: string;
  note: string;
}

function formatMoney(v: number): string {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(v);
}

function formatDate(dateStr: string | undefined | null): string {
  if (!dateStr) return '-';
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return '-';
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = d.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

function toDateInputValue(dateStr: string | undefined | null): string {
  if (!dateStr) return '';
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return '';
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = d.getFullYear();
  return `${yyyy}-${mm}-${dd}`;
}

function pageNumbers(current: number, total: number): (number | 'dots')[] {
  if (total <= 7) return Array.from({ length: total }, (_, i) => i + 1);
  const pages: (number | 'dots')[] = [];
  pages.push(1);
  if (current > 3) pages.push('dots');
  const start = Math.max(2, current - 1);
  const end = Math.min(total - 1, current + 1);
  for (let i = start; i <= end; i++) pages.push(i);
  if (current < total - 2) pages.push('dots');
  pages.push(total);
  return pages;
}

const initialFormValues: FormValues = {
  categoryCode: '',
  planAmount: 0,
  actualAmount: 0,
  reasonCode: '',
  reasonDetail: '',
  owner: '',
  status: 'Open',
  deadline: '',
  note: '',
};

export default function VarianceLogPage() {
  const dispatch = useAppDispatch();

  const [data, setData] = useState<VarianceLogEntryDto[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<VarianceLogEntryDto | null>(null);
  const [formValues, setFormValues] = useState<FormValues>(initialFormValues);
  const [formErrors, setFormErrors] = useState<Record<string, string>>({});
  const [currentPage, setCurrentPage] = useState(1);

  const updateField = (field: keyof FormValues, value: string | number) => {
    setFormValues(prev => ({ ...prev, [field]: value }));
    if (formErrors[field]) {
      setFormErrors(prev => {
        const next = { ...prev };
        delete next[field];
        return next;
      });
    }
  };

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const result = await fpcService.getVarianceList();
      setData(result);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const openModal = (record?: VarianceLogEntryDto) => {
    if (record) {
      setEditing(record);
      setFormValues({
        categoryCode: record.categoryCode,
        planAmount: record.planAmount,
        actualAmount: record.actualAmount,
        reasonCode: record.reasonCode ?? '',
        reasonDetail: record.reasonDetail ?? '',
        owner: record.owner ?? '',
        status: record.status,
        deadline: toDateInputValue(record.deadline),
        note: record.note ?? '',
      });
    } else {
      setEditing(null);
      setFormValues({ ...initialFormValues });
    }
    setFormErrors({});
    setModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    await fpcService.deleteVariance(id);
    dispatchAppToast(dispatch, { message: 'Đã xóa bản ghi chênh lệch', type: 'success' });
    fetchData();
  };

  const handleSubmit = async () => {
    const errors: Record<string, string> = {};
    if (!editing && !formValues.categoryCode.trim()) {
      errors.categoryCode = 'Vui lòng nhập mã danh mục';
    }
    if (Object.keys(errors).length > 0) {
      setFormErrors(errors);
      return;
    }

    try {
      if (editing) {
        const dto: UpdateVarianceLogDto = {
          reasonCode: formValues.reasonCode || undefined,
          reasonDetail: formValues.reasonDetail || undefined,
          owner: formValues.owner || undefined,
          status: formValues.status || undefined,
          deadline: formValues.deadline
            ? new Date(formValues.deadline + 'T00:00:00').toISOString()
            : undefined,
          note: formValues.note || undefined,
        };
        await fpcService.updateVariance(editing.id, dto);
        dispatchAppToast(dispatch, { message: 'Đã cập nhật bản ghi chênh lệch', type: 'success' });
      } else {
        const dto: CreateVarianceLogDto = {
          categoryCode: formValues.categoryCode,
          planAmount: formValues.planAmount,
          actualAmount: formValues.actualAmount,
          reasonCode: formValues.reasonCode || undefined,
          reasonDetail: formValues.reasonDetail || undefined,
          owner: formValues.owner || undefined,
          deadline: formValues.deadline
            ? new Date(formValues.deadline + 'T00:00:00').toISOString()
            : undefined,
          note: formValues.note || undefined,
        };
        await fpcService.createVariance(dto);
        dispatchAppToast(dispatch, { message: 'Đã tạo bản ghi chênh lệch', type: 'success' });
      }
      setModalOpen(false);
      fetchData();
    } catch {
      /* error handled by middleware or global handler */
    }
  };

  const totalPages = Math.ceil(data.length / PAGE_SIZE);
  const paginatedData = data.slice(
    (currentPage - 1) * PAGE_SIZE,
    currentPage * PAGE_SIZE,
  );

  return (
    <div className={styles.page}>
      <Title>Nhật ký chênh lệch</Title>

      <Card style={{ marginBottom: 16 }}>
        <Button variant="primary" onClick={() => openModal()}>
          <i className="fas fa-plus" /> Thêm bản ghi chênh lệch
        </Button>
      </Card>

      {loading ? (
        <div style={{ textAlign: 'center', padding: 48 }}>
          <Spin />
        </div>
      ) : (
        <>
          <table className={styles.table}>
            <thead>
              <tr>
                <th style={{ width: 180, textAlign: 'left' }}>Danh mục</th>
                <th style={{ width: 140, textAlign: 'right' }}>Kế hoạch</th>
                <th style={{ width: 140, textAlign: 'right' }}>Thực tế</th>
                <th style={{ width: 160, textAlign: 'right' }}>Chênh lệch</th>
                <th style={{ width: 120, textAlign: 'left' }}>Lý do</th>
                <th style={{ width: 120, textAlign: 'left' }}>Người phụ trách</th>
                <th style={{ width: 120, textAlign: 'left' }}>Trạng thái</th>
                <th style={{ width: 110, textAlign: 'left' }}>Hạn</th>
                <th style={{ width: 100, textAlign: 'center' }} />
              </tr>
            </thead>
            <tbody>
              {paginatedData.length === 0 ? (
                <tr>
                  <td colSpan={9} style={{ textAlign: 'center', padding: 24 }}>
                    <Text>Không có dữ liệu</Text>
                  </td>
                </tr>
              ) : (
                paginatedData.map((record) => (
                  <tr key={record.id}>
                    <td>{record.categoryName}</td>
                    <td style={{ textAlign: 'right' }}>{formatMoney(record.planAmount)}</td>
                    <td style={{ textAlign: 'right' }}>{formatMoney(record.actualAmount)}</td>
                    <td style={{ textAlign: 'right' }}>
                      <span
                        style={{
                          color: record.variance >= 0 ? '#52c41a' : '#ff4d4f',
                          fontWeight: 600,
                        }}
                      >
                        {formatMoney(record.variance)}
                      </span>
                    </td>
                    <td>{record.reasonCode || '-'}</td>
                    <td>{record.owner || '-'}</td>
                    <td>
                      <Tag color={STATUS_COLORS[record.status] || 'default'}>
                        {STATUS_LABELS[record.status] || record.status}
                      </Tag>
                    </td>
                    <td>{formatDate(record.deadline)}</td>
                    <td style={{ textAlign: 'center' }}>
                      <Space>
                        <button
                          className={styles.linkBtn}
                          onClick={() => openModal(record)}
                        >
                          <i className="fas fa-edit" />
                        </button>
                        <Popconfirm
                          title="Xóa bản ghi này?"
                          onConfirm={() => handleDelete(record.id)}
                        >
                          <button className={styles.linkBtn}>
                            <i className="fas fa-trash" />
                          </button>
                        </Popconfirm>
                      </Space>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>

          <div
            style={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              marginTop: 16,
            }}
          >
            <Text>Tổng: {data.length} bản ghi</Text>

            {totalPages > 1 && (
              <div style={{ display: 'flex', gap: 4, alignItems: 'center' }}>
                <Button
                  variant="secondary"
                  size="sm"
                  disabled={currentPage <= 1}
                  onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                >
                  Trước
                </Button>
                {pageNumbers(currentPage, totalPages).map((p, i) =>
                  p === 'dots' ? (
                    <Text key={`dots-${i}`}>...</Text>
                  ) : (
                    <Button
                      key={p}
                      variant={p === currentPage ? 'primary' : 'secondary'}
                      size="sm"
                      onClick={() => setCurrentPage(p)}
                    >
                      {p}
                    </Button>
                  ),
                )}
                <Button
                  variant="secondary"
                  size="sm"
                  disabled={currentPage >= totalPages}
                  onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
                >
                  Sau
                </Button>
              </div>
            )}
          </div>
        </>
      )}

      <Modal
        title={editing ? 'Cập nhật nhật ký chênh lệch' : 'Thêm nhật ký chênh lệch'}
        open={modalOpen}
        onOk={handleSubmit}
        onCancel={() => setModalOpen(false)}
        width={600}
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {/* Category Code */}
          <div>
            <label className={styles.fieldLabel}>
              Mã danh mục <span style={{ color: 'red' }}>*</span>
            </label>
            <input
              type="text"
              className={styles.input}
              placeholder="VD: SALES_REVENUE"
              value={formValues.categoryCode}
              onChange={(e) => updateField('categoryCode', e.target.value)}
              disabled={!!editing}
            />
            {formErrors.categoryCode && (
              <div className={styles.fieldError}>{formErrors.categoryCode}</div>
            )}
          </div>

          {/* Plan Amount / Actual Amount side by side */}
          <div style={{ display: 'flex', gap: 16 }}>
            <div style={{ flex: 1 }}>
              <label className={styles.fieldLabel}>
                Số kế hoạch <span style={{ color: 'red' }}>*</span>
              </label>
              <input
                type="number"
                className={styles.input}
                value={formValues.planAmount}
                onChange={(e) => updateField('planAmount', Number(e.target.value))}
                disabled={!!editing}
              />
            </div>
            <div style={{ flex: 1 }}>
              <label className={styles.fieldLabel}>
                Số thực tế <span style={{ color: 'red' }}>*</span>
              </label>
              <input
                type="number"
                className={styles.input}
                value={formValues.actualAmount}
                onChange={(e) => updateField('actualAmount', Number(e.target.value))}
                disabled={!!editing}
              />
            </div>
          </div>

          {/* Reason Code */}
          <div>
            <label className={styles.fieldLabel}>Mã lý do</label>
            <select
              className={styles.input}
              value={formValues.reasonCode}
              onChange={(e) => updateField('reasonCode', e.target.value)}
            >
              <option value="">Chọn lý do</option>
              {REASON_OPTIONS.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>
          </div>

          {/* Reason Detail */}
          <div>
            <label className={styles.fieldLabel}>Chi tiết lý do</label>
            <textarea
              className={styles.textarea}
              rows={2}
              value={formValues.reasonDetail}
              onChange={(e) => updateField('reasonDetail', e.target.value)}
            />
          </div>

          {/* Owner / Status side by side */}
          <div style={{ display: 'flex', gap: 16 }}>
            <div style={{ flex: 1 }}>
              <label className={styles.fieldLabel}>Người phụ trách</label>
              <input
                type="text"
                className={styles.input}
                placeholder="VD: Nguyễn Văn A"
                value={formValues.owner}
                onChange={(e) => updateField('owner', e.target.value)}
              />
            </div>
            {editing && (
              <div style={{ flex: 1 }}>
                <label className={styles.fieldLabel}>Trạng thái</label>
                <select
                  className={styles.input}
                  value={formValues.status}
                  onChange={(e) => updateField('status', e.target.value)}
                >
                  {STATUS_OPTIONS.map((opt) => (
                    <option key={opt.value} value={opt.value}>
                      {opt.label}
                    </option>
                  ))}
                </select>
              </div>
            )}
          </div>

          {/* Deadline */}
          <div>
            <label className={styles.fieldLabel}>Hạn xử lý</label>
            <input
              type="date"
              className={styles.input}
              value={formValues.deadline}
              onChange={(e) => updateField('deadline', e.target.value)}
            />
          </div>

          {/* Note */}
          <div>
            <label className={styles.fieldLabel}>Ghi chú</label>
            <textarea
              className={styles.textarea}
              rows={2}
              value={formValues.note}
              onChange={(e) => updateField('note', e.target.value)}
            />
          </div>
        </div>
      </Modal>
    </div>
  );
}
